// Hand-written example scenarios, one per dialect (plus a teardown one).
// These exist to exercise and document the format and its two executors;
// they are NOT conversions of existing animations or tests (those will be
// generated by scripts). Semantically they follow the same behaviors the
// hand-written unit tests pin down, so they must pass against the real
// implementations.

export const exampleMapScenario = {
  id: 'example-map',
  helper: 'map',
  label: 'Example: map then done',
  ticks: [
    {
      note: 'first next() pulls the source once',
      steps: [
        { caption: 'Consumer calls <code>.next()</code>.', events: [{ type: 'next', result: 'r0' }] },
        { caption: 'The pull is forwarded to <b>Underlying</b>.', events: [{ type: 'pull', pull: 'u0' }] },
      ],
    },
    {
      note: 'the value is handed to the mapper',
      steps: [
        {
          caption: 'Underlying settles with <code>1</code>; the mapper runs.',
          events: [
            { type: 'settle', pull: 'u0', value: 1 },
            { type: 'fn', call: 'p0', arg: 1, from: 'u0' },
          ],
        },
      ],
    },
    {
      note: 'the mapped value is delivered',
      steps: [
        {
          caption: '<code>f(1)</code> settles to <code>10</code>, which resolves the first <code>.next()</code>.',
          events: [
            { type: 'fn-settle', call: 'p0', value: 10 },
            { type: 'result', result: 'r0', value: 10, from: 'p0' },
          ],
        },
      ],
    },
    {
      note: 'a second next() pulls again',
      steps: [
        { caption: 'Consumer pulls again.', events: [{ type: 'next', result: 'r1' }] },
        { caption: 'Forwarded to <b>Underlying</b>.', events: [{ type: 'pull', pull: 'u1' }] },
      ],
    },
    {
      note: 'done propagates, source left open',
      steps: [
        {
          caption: 'The source is exhausted; the completion passes through.',
          events: [
            { type: 'settle', pull: 'u1', done: true },
            { type: 'result', result: 'r1', done: true },
            { type: 'tombstone', target: 'underlying' },
            { type: 'tombstone', target: 'result' },
          ],
        },
      ],
    },
  ],
};

export const exampleFilterScenario = {
  id: 'example-filter',
  helper: 'filter',
  label: 'Example: drop, buffer, deliver in order',
  ticks: [
    {
      note: 'first next() pulls the source',
      steps: [
        { caption: 'Consumer calls <code>.next()</code>.', events: [{ type: 'next', result: 'r0' }] },
        { caption: 'The pull is forwarded.', events: [{ type: 'pull', pull: 'u0' }] },
      ],
    },
    {
      note: 'a concurrent second next() pulls again',
      steps: [
        { caption: 'A second <code>.next()</code>, before the first resolves.', events: [{ type: 'next', result: 'r1' }] },
        { caption: 'A second pull goes out.', events: [{ type: 'pull', pull: 'u1' }] },
      ],
    },
    {
      note: 'the second value arrives first and runs the predicate',
      steps: [
        {
          caption: '<code>B</code> arrives before <code>A</code> and runs <code>pred(B)</code>.',
          events: [
            { type: 'settle', pull: 'u1', value: 'B' },
            { type: 'fn', call: 'p0', arg: 'B', from: 'u1' },
          ],
        },
      ],
    },
    {
      note: 'the dropped value triggers a replacement pull',
      steps: [
        {
          caption: '<code>pred(B)</code> settles to <code>false</code> — <code>B</code> is rejected.',
          events: [{ type: 'fn-settle', call: 'p0', verdict: false }],
        },
        {
          caption: '<code>B</code> is discarded; the filter pulls again.',
          events: [
            { type: 'compact', pull: 'u1' },
            { type: 'pull', pull: 'u2' },
          ],
        },
      ],
    },
    {
      note: 'the replacement value arrives and runs the predicate',
      steps: [
        {
          caption: '<code>C</code> arrives (still ahead of <code>A</code>) and runs <code>pred(C)</code> in the freed row.',
          events: [
            { type: 'settle', pull: 'u2', value: 'C' },
            { type: 'fn', call: 'p1', arg: 'C', from: 'u2' },
          ],
        },
      ],
    },
    {
      note: 'a later passing value cannot settle ahead of the earlier call',
      steps: [
        {
          caption: '<code>pred(C)</code> passes, but <code>C</code> is buffered behind the pending <code>A</code>.',
          events: [{ type: 'fn-settle', call: 'p1', verdict: true }],
        },
      ],
    },
    {
      note: 'the first value finally arrives',
      steps: [
        {
          caption: '<code>A</code> arrives at last and runs <code>pred(A)</code>.',
          events: [
            { type: 'settle', pull: 'u0', value: 'A' },
            { type: 'fn', call: 'p2', arg: 'A', from: 'u0' },
          ],
        },
      ],
    },
    {
      note: 'both results deliver in order',
      steps: [
        {
          caption: '<code>pred(A)</code> passes too; both results settle in source order — <code>A</code> then <code>C</code>.',
          events: [
            { type: 'fn-settle', call: 'p2', verdict: true },
            { type: 'result', result: 'r0', value: 'A', from: 'p2' },
            { type: 'result', result: 'r1', value: 'C', from: 'p1' },
          ],
        },
      ],
    },
  ],
};

export const exampleFilterClosingScenario = {
  id: 'example-filter-closing',
  helper: 'filter',
  label: 'Example: return() mid-flight',
  ticks: [
    {
      note: 'a pull is in flight',
      steps: [
        { caption: 'Consumer calls <code>.next()</code>.', events: [{ type: 'next', result: 'r0' }] },
        { caption: 'The pull is forwarded.', events: [{ type: 'pull', pull: 'u0' }] },
      ],
    },
    {
      note: 'return() closes the source and resolves',
      steps: [
        {
          caption: 'The teardown band slides in; the consumer calls <code>.return()</code>.',
          events: [
            { type: 'open-closing' },
            { type: 'return', result: 'ret' },
          ],
        },
        {
          caption: 'The helper closes the source: <code>underlying.return()</code>.',
          events: [{ type: 'close', target: 'source' }],
        },
        {
          caption: 'Both iterators are closed — tombstones.',
          events: [
            { type: 'tombstone', target: 'underlying' },
            { type: 'tombstone', target: 'result' },
          ],
        },
      ],
    },
    {
      steps: [
        {
          caption: '<code>underlying.return()</code> settles, and the consumer’s <code>.return()</code> resolves done.',
          events: [
            { type: 'close-settled', target: 'source' },
            { type: 'result', result: 'ret', done: true },
          ],
        },
      ],
    },
    {
      note: 'the already-requested value still runs the predicate',
      steps: [
        {
          caption: '<code>A</code> still arrives and runs <code>pred(A)</code> — <code>return()</code> is not a cancel.',
          events: [
            { type: 'settle', pull: 'u0', value: 'A' },
            { type: 'fn', call: 'p0', arg: 'A', from: 'u0' },
          ],
        },
      ],
    },
    {
      note: 'the already-requested passing value is delivered',
      steps: [
        {
          caption: '<code>pred(A)</code> passes and the first <code>.next()</code> delivers <code>A</code>.',
          events: [
            { type: 'fn-settle', call: 'p0', verdict: true },
            { type: 'result', result: 'r0', value: 'A', from: 'p0' },
          ],
        },
      ],
    },
  ],
};

export const exampleFlatMapScenario = {
  id: 'example-flatmap',
  helper: 'flatMap',
  label: 'Example: coalesced demand, out-of-order inner values',
  ticks: [
    {
      note: 'two concurrent calls cause a single underlying pull',
      steps: [
        { caption: 'Consumer calls <code>.next()</code>.', events: [{ type: 'next', result: 'r0' }] },
        { caption: 'A second <code>.next()</code> — but <code>flatMap</code> can’t pull ahead.', events: [{ type: 'next', result: 'r1' }] },
        { caption: 'A single pull is forwarded to <b>Underlying</b>.', events: [{ type: 'pull', pull: 'u0' }] },
      ],
    },
    {
      note: 'the underlying value is handed to the mapper',
      steps: [
        {
          caption: 'Underlying settles with <code>1</code>; the mapper <code>f(1)</code> runs.',
          events: [
            { type: 'settle', pull: 'u0', value: 1 },
            { type: 'fn', call: 'p0', arg: 1, from: 'u0' },
          ],
        },
      ],
    },
    {
      note: 'the inner iterator is pulled once per outstanding call',
      steps: [
        {
          caption: '<code>f(1)</code> resolves to an inner iterator, which replaces its box.',
          events: [{ type: 'fn-settle', call: 'p0', iterator: 'A' }],
        },
        {
          caption: 'Both outstanding calls drive it: two concurrent inner pulls.',
          events: [
            { type: 'inner-pull', pull: 'a0', iterator: 'A' },
            { type: 'inner-pull', pull: 'a1', iterator: 'A' },
          ],
        },
      ],
    },
    {
      note: 'a later inner value cannot settle ahead of an earlier one',
      steps: [
        {
          caption: 'The <i>second</i> inner pull settles first — <code>a1</code> is buffered.',
          events: [{ type: 'settle', pull: 'a1', value: 'a1' }],
        },
      ],
    },
    {
      note: 'once the earlier value arrives, both settle in call order',
      steps: [
        {
          caption: '<code>a0</code> arrives; both results deliver in order.',
          events: [
            { type: 'settle', pull: 'a0', value: 'a0' },
            { type: 'result', result: 'r0', value: 'a0', from: 'a0' },
            { type: 'result', result: 'r1', value: 'a1', from: 'a1' },
          ],
        },
      ],
    },
    {
      note: 'a third call pulls the same inner iterator',
      steps: [
        { caption: 'Consumer pulls a third time.', events: [{ type: 'next', result: 'r2' }] },
        { caption: 'The current inner iterator is pulled again.', events: [{ type: 'inner-pull', pull: 'a2', iterator: 'A' }] },
      ],
    },
    {
      note: 'inner done redirects demand to a new underlying pull',
      steps: [
        {
          caption: 'The inner iterator is exhausted; <code>flatMap</code> advances to the next source value.',
          events: [
            { type: 'settle', pull: 'a2', done: true },
            { type: 'pull', pull: 'u1' },
          ],
        },
      ],
    },
    {
      note: 'underlying done is terminal and propagates',
      steps: [
        {
          caption: 'The source itself is exhausted — the third <code>.next()</code> resolves done.',
          events: [
            { type: 'settle', pull: 'u1', done: true },
            { type: 'result', result: 'r2', done: true },
            { type: 'tombstone', target: 'underlying' },
            { type: 'tombstone', target: 'result' },
          ],
        },
      ],
    },
  ],
};

export const exampleScenarios = [
  exampleMapScenario,
  exampleFilterScenario,
  exampleFilterClosingScenario,
  exampleFlatMapScenario,
];
